INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES
(gen_random_uuid(), 'pv', 26, 1, NULL, 'Anselmo de Cantuária em Pv 26:1', 'Anselmo de Cantuária interpreta este versículo a partir de a síntese entre fé, razão e vida santa. Em Provérbios 26, Deus revela adoração, sabedoria e temor do Senhor de forma pastoral e transformadora, promovendo fidelidade na aliança. A verdade bíblica forma caráter, culto e missão. Aplicação: responda com oração, disciplina espiritual e serviço cristão.', 'Anselmo de Cantuária', 'commentary', '#6B4F2A', NOW()),
(gen_random_uuid(), 'pv', 27, 1, NULL, 'William Perkins em Pv 27:1', 'William Perkins destaca a piedade prática e a santificação do coração. Em Provérbios 27, o foco recai sobre adoração, sabedoria e temor do Senhor e chama a igreja para vida de oração. O texto orienta a fé para uma obediência concreta e perseverante. Aplicação: receba esta verdade com fé, arrependimento e esperança ativa.', 'William Perkins', 'commentary', '#2E8B57', NOW()),
(gen_random_uuid(), 'pv', 28, 1, NULL, 'B. B. Warfield em Pv 28:1', 'B. B. Warfield interpreta este versículo a partir de a coerência doutrinária aplicada à vida cristã. Em Provérbios 28, Deus revela adoração, sabedoria e temor do Senhor de forma pastoral e transformadora, promovendo santidade prática. A verdade bíblica forma caráter, culto e missão. Aplicação: responda com oração, disciplina espiritual e serviço cristão.', 'B. B. Warfield', 'commentary', '#1D4ED8', NOW()),
(gen_random_uuid(), 'pv', 29, 1, NULL, 'Tomás de Aquino em Pv 29:1', 'Segundo Tomás de Aquino, a síntese entre fé, razão e vida santa ilumina o sentido deste texto. Provérbios 29 mostra que adoração, sabedoria e temor do Senhor sustenta a caminhada da fé, especialmente em obediência da fé. A doutrina aqui conduz à devoção e à perseverança. Aplicação: firme-se nas promessas divinas e pratique a verdade com humildade.', 'Tomás de Aquino', 'commentary', '#6B4F2A', NOW()),
(gen_random_uuid(), 'pv', 30, 1, NULL, 'Thomas Goodwin em Pv 30:1', 'Na leitura de Thomas Goodwin, vemos a piedade prática e a santificação do coração. Provérbios 30 evidencia adoração, sabedoria e temor do Senhor como eixo da vida do povo de Deus, com ênfase em adoração reverente. A passagem confronta o coração e organiza a prática diária do discípulo. Aplicação: submeta sua vontade à Palavra e caminhe em fidelidade.', 'Thomas Goodwin', 'commentary', '#2E8B57', NOW()),
(gen_random_uuid(), 'pv', 31, 1, NULL, 'Alexander Maclaren em Pv 31:1', 'Segundo Alexander Maclaren, a coerência doutrinária aplicada à vida cristã ilumina o sentido deste texto. Provérbios 31 mostra que adoração, sabedoria e temor do Senhor sustenta a caminhada da fé, especialmente em amor fraternal. A doutrina aqui conduz à devoção e à perseverança. Aplicação: firme-se nas promessas divinas e pratique a verdade com humildade.', 'Alexander Maclaren', 'commentary', '#1D4ED8', NOW()),
(gen_random_uuid(), 'ec', 1, 1, NULL, 'João Calvino em Ec 1:1', 'João Calvino interpreta este versículo a partir de a centralidade das Escrituras e da graça soberana. Em Eclesiastes 1, Deus revela adoração, sabedoria e temor do Senhor de forma pastoral e transformadora, promovendo justiça com misericórdia. A verdade bíblica forma caráter, culto e missão. Aplicação: responda com oração, disciplina espiritual e serviço cristão.', 'João Calvino', 'commentary', '#800080', NOW()),
(gen_random_uuid(), 'ec', 2, 1, NULL, 'John Brown of Haddington em Ec 2:1', 'John Brown of Haddington destaca a piedade prática e a santificação do coração. Em Eclesiastes 2, o foco recai sobre adoração, sabedoria e temor do Senhor e chama a igreja para perseverança na tribulação. O texto orienta a fé para uma obediência concreta e perseverante. Aplicação: receba esta verdade com fé, arrependimento e esperança ativa.', 'John Brown of Haddington', 'commentary', '#2E8B57', NOW()),
(gen_random_uuid(), 'ec', 3, 1, NULL, 'Albert Barnes em Ec 3:1', 'Albert Barnes interpreta este versículo a partir de a exposição textual com aplicação pastoral objetiva. Em Eclesiastes 3, Deus revela adoração, sabedoria e temor do Senhor de forma pastoral e transformadora, promovendo fidelidade na aliança. A verdade bíblica forma caráter, culto e missão. Aplicação: responda com oração, disciplina espiritual e serviço cristão.', 'Albert Barnes', 'commentary', '#B45309', NOW()),
